LocalizationManager:add_localized_strings({
    --intro
    ["trai_intro_01_01"] = "Давайте разберёмся. У вас есть парень по имени Даллас, который не из Далласа, и парень по имени Хьюстон, который никогда не был в Хьюстоне?",
    ["trai_intro_01_02"] = "Чертовски странно, правда? По-моему, они вообще из Чикаго.",
    ["trai_intro_01_03"] = "Хм. Ну, раз они справляются со своей работой, пусть называют себя как им вздумается. По мне так - без разницы.",
    ["trai_intro_02_01"] = "Как ты узнал об этих печатных платах? Если этим занимается армия, то получить такую информацию, наверное, было не так-то просто.",
    ["trai_intro_02_02"] = "Мне нравится быть в курсе всего, что происходит в моих краях. У меня глаза по всему Техасу, а у моей контрабандной сети есть партнёры на самых высоких должностях.",
    ["trai_intro_02_03"] = "Ну, если здесь всё будет хорошо, мы бы хотели как-нибудь встретиться с этими партнёрами. Всегда стараемся быть полезными. За правильную цену.",
    ["trai_intro_03_01"] = "Ты, похоже, совсем не нервничаешь перед предстоящим противостоянием с Армией. Совсем не нервничаешь.",
    ["trai_intro_03_02"] = "Мы уже справились с немалым количеством серьезных противников. Murkywater. Триада \"Золотой Кинжал\". Мы даже ударили по ФБР.",
    ["trai_intro_03_03"] = "Чёрт возьми! Вы ребята из высшей лиги! Что дальше? Форт-Нокс?",
    ["trai_intro_03_04"] = "Ха-ха... Да...",

["gem_trai_01_01"] = "Мои источники говорят, что ворота под напряжением. Если не хотите зажариться, отключите электричество, прежде чем трогать их.",
["gem_trai_01_02"] = "Внимание, ворота находятся под электрическим током. Не пытайтесь их разрезать, пока не отключите питание.",
["gem_trai_01_03"] = "Осторожно. Мне сообщили, что ворота под напряжением. Отключите питание или найдите другой путь.",
["gem_trai_02_01"] = "Совет: металл на крыше поезда самый тонкий. Горелка расплавит его как масло.",
["gem_trai_02_02"] = "Подсказка: используйте горелку на крыше вагона. Там металл самый слабый.",
["gem_trai_02_03"] = "Мой контакт говорит, что броня поезда тоньше всего на крыше. Попробуйте прожечь там.",
["gem_trai_03_01"] = "Вы не сможете уйти по дороге из-за армейских блокпостов. Так что вы собираетесь снять пластины с этого поезда... и сбежать на другом? Не могу дождаться, чтобы это увидеть.",
["gem_trai_03_02"] = "Вы действительно хотите угнать поезд, чтобы обойти армейские блокпосты? Увижу - поверю.",
["gem_trai_03_03"] = "Если вам удастся этот побег, вы выведете термин \"ограбление поезда\" на совершенно новый уровень.",
["gem_trai_04_01"] = "Вау. Это было... просто... ВАУ.",
["gem_trai_04_02"] = "Что это было, черт возьми?!",
["gem_trai_04_03"] = "Это был лучший из худших техасских акцентов, которые я когда-либо слышал!",
["gem_trai_05_01"] = "Эти ворота под напряжением. Отключите питание или найдите другой способ войти. Поторопитесь, друзья! Эти пластины вот-вот уйдут!",
["gem_trai_05_02"] = "Не трогайте ворота, пока не отключите электричество. Вы не сможете украсть пластины, если вас поджарит ток.",
["gem_trai_05_03"] = "Поторопитесь, друзья! И помните: эти ворота ударят током, если не отключить питание.",
["gem_trai_06_01"] = "Бум! Эти пластины теперь никуда не денутся без нас. Отличная работа!",
["gem_trai_06_02"] = "Отлично! Эти поезда остаются на месте. Хороший ход, друзья.",
["gem_trai_06_03"] = "Отличная работа! Эти пластины останутся тут, пока мы не будем готовы.",
["gem_trai_07_01"] = "К вашему сведению: металл на этих поездах самый слабый на крыше. Горелка должна легко прожечь его.",
["gem_trai_07_02"] = "Мне сказали, что вагоны слабее всего на крыше. Попробуйте прорезать там.",
["gem_trai_07_03"] = "Мой контакт говорит, что вам будет легче, если вы прожжете вагоны на крыше.",
["gem_trai_08_01"] = "Вы не можете уйти по дороге из-за армейских блокпостов, и вы перекрыли большинство путей этим трубопроводом. Как вы собираетесь это провернуть?",
["gem_trai_08_02"] = "Армия заблокировала дороги. Большинство путей перекрыты. Не знаю, какой у вас план, но вам лучше действовать быстро.",
["gem_trai_08_03"] = "С армией на дорогах и трубопроводом на путях я не знаю, как вы выберетесь из этого. Надеюсь, у вас есть план.",
["gem_trai_09_01"] = "Ничего себе! Он действительно может выдержать эту штуковину! Просто невероятно...",
["gem_trai_09_02"] = "Вот это да! Честно, я не думала, что это сработает.",
["gem_trai_09_03"] = "Вы шутите! Это невероятно мощный кран!",
["gem_trai_10_01"] = "Быстрее, друзья! Поступила информация, что армия собирается взорвать железнодорожные пути. Группа подрывников уже на подходе!",
["gem_trai_10_02"] = "Армия посылает команду, чтобы взорвать пути! Если вы не выберетесь быстро, то останетесь тут навсегда!",
["gem_trai_10_03"] = "Похоже, армия разгадала ваш план побега! Они готовятся взорвать пути. Уходите оттуда!",
["gem_trai_11_01"] = "Странная фотография, чтобы просто так повесить. Может быть, там стоит что-то проверить?",
["gem_trai_12_01"] = "У каждого ключа есть замок. Видите какие-нибудь подсказки, куда он может подойти?",
["gem_trai_13_01"] = "Так вот, для чего нужна была эта звезда! Я бы не выбрасывал этот USB. Возможно, это часть чего-то большего.",
["gem_trai_cnc_01"] = "Денежный поезд уходит со станции!",
["gem_trai_cnc_02"] = "Нашел новую работу, которая как раз вам подойдет.",
["gem_trai_cnc_03"] = "Я не знаю, как вы это провернете, но если кто-то и сможет, то только вы.",
["loc_trai_01_01"] = "Время для старомодного ограбления поезда! Должно быть несколько способов пройти через передние ворота. Выбирайте, друзья.",
["loc_trai_01_02"] = "Используйте любой способ, чтобы пройти через передние ворота. Способов больше, чем кажется... Брр, жуткое выражение, правда?",
["loc_trai_01_03"] = "Впереди депо. Охрана на передних воротах выглядит не слишком серьезной. Покажите, на что способны.",
["loc_trai_02_01"] = "Пройдите через передние ворота любым способом.",
["loc_trai_02_02"] = "Вы можете прорезать ворота, если сначала отключите электричество.",
["loc_trai_02_03"] = "Интересно, есть ли способ перебраться через эти ворота...",
["loc_trai_03_01"] = "Следующие ворота выглядят надежно. Хм... Если найдете рацию рабочего, я могу попытаться обмануть охрану, чтобы нас впустили.",
["loc_trai_03_02"] = "Незаметно пройти через вторые ворота не получится. Придется обмануть охрану, чтобы они их открыли. Поискать рацию рабочего?",
["loc_trai_03_03"] = "Можете раздобыть рацию рабочего? Тогда, возможно, мы пройдем через вторые ворота, даже не поднимая пальца.",
["loc_trai_04_01"] = "У нас тут опоздавшие ребята из техобслуживания. Открывайте.",
["loc_trai_04_02"] = "Какой-то сержант пришел с проверкой безопасности. Пропустите его.",
["loc_trai_04_03"] = "Моя смена окончена, но я оставил ключи от машины в шкафчике. Можете меня впустить?",
["loc_trai_05_01"] = "Найдите рацию, и я попробую договориться об открытии ворот.",
["loc_trai_05_02"] = "Удалось найти рацию?",
["loc_trai_05_03"] = "Наверняка один из рабочих оставил рацию где-то поблизости.",
["loc_trai_06_01"] = "Хорошо. Направляйтесь к складу и найдите способ попасть в административный офис. Там должен быть грузовой манифест, который приведет нас прямо к пластинам.",
["loc_trai_06_02"] = "Должен быть грузовой манифест, который подскажет, в каком поезде находятся пластины. Проверьте административный офис на складе.",
["loc_trai_06_03"] = "Если вы попадете в административный офис на складе, то сможете получить доступ к грузовому манифесту с информацией о пластинах.",
["loc_trai_07_01"] = "Для офиса нужен код доступа. Осмотрите склад. Обычно такие подсказки где-то есть.",
["loc_trai_07_02"] = "Для двери офиса нужен код. Вы где-нибудь видели его записанным?",
["loc_trai_07_03"] = "Дверь административного офиса закрыта на кодовый замок? Как неожиданно. Поищите код.",
["loc_trai_08_01"] = "Информация, которая нам нужна, находится в административном офисе.",
["loc_trai_08_02"] = "Нам действительно нужно попасть в этот офис.",
["loc_trai_08_03"] = "Вы уже нашли код для офиса?",
["loc_trai_09_01"] = "Взломайте админский компьютер, чтобы получить доступ к манифесту. Нам нужно узнать, под какой компанией армия прячет свои грузы.",
["loc_trai_09_02"] = "Армия маскирует свои вагоны под грузовую компанию. Взломайте админский компьютер, и манифест укажет нам правильное направление.",
["loc_trai_09_03"] = "В манифесте на админском компьютере указана армейская подставная компания. Получите к нему доступ.",
["loc_trai_10_01"] = "Давайте откроем этот манифест, а?",
["loc_trai_10_02"] = "Посмотрите на грузовой манифест.",
["loc_trai_10_03"] = "Взломайте админский компьютер.",
["loc_trai_11_01"] = "Теперь мы знаем, какой поезд нужен, но наш контакт сказал, что вагоны оснащены датчиками движения. Эти маленькие засранцы подключены к консоли управления где-то в депо.",
["loc_trai_11_02"] = "Прежде чем попадем внутрь вагонов, нужно разобраться с датчиками движения на поезде. Контакт Джеммы говорит, что они связаны с консолью управления где-то в депо.",
["loc_trai_11_03"] = "У нас есть данные, что армейские вагоны оснащены датчиками движения. Осмотритесь в поисках консоли управления, чтобы отключить их.",
["loc_trai_12_01"] = "Найдите консоль, управляющую датчиками движения. Пока они активны, мы ничего не сделаем.",
["loc_trai_12_02"] = "Нужно отключить датчики движения. Осмотритесь в поисках консоли управления.",
["loc_trai_12_03"] = "Мы не сможем добраться до печатных пластин, пока не отключим датчики движения.",
["loc_trai_13_01"] = "Я видел такие технологии раньше. Эти армейцы подключили консоль к панели-генератору ключей. Если вы найдете её, то получите код доступа.",
["loc_trai_13_02"] = "Я узнаю эту систему безопасности. Код доступа к консоли генерируется панелью-ключгенератором, которая должна быть где-то поблизости. Давайте её найдем.",
["loc_trai_13_03"] = "Давно такого не видел. Консоль связана с устройством, называемым панелью-ключгенератором. Нужно её найти, если хотите отключить датчики.",
["loc_trai_14_01"] = "Где-то здесь должна быть панель-ключгенератор.",
["loc_trai_14_02"] = "Панель-ключгенератор должна выдать код для датчиков движения.",
["loc_trai_14_03"] = "Где-то поблизости точно есть эта чёртова панель-ключгенератор.",
["loc_trai_15_01"] = "Видите эту сетку огней? Она должна прямо соответствовать коду. Вернитесь к консоли и введите его.",
["loc_trai_15_02"] = "Расположение этих огней должно соответствовать коду для консоли управления. Теперь мы можем отключить датчики движения!",
["loc_trai_15_03"] = "Код консоли должен совпадать с расположением огней на этой панели. Возвращайтесь и вводите.",
["loc_trai_16_01"] = "Теперь можно безопасно подойти к вагонам. Ищите те, которые маркированы именем грузовой компании из манифеста.",
["loc_trai_16_02"] = "Датчики движения отключены! Теперь мы можем попасть внутрь вагонов. Ищите те, что отмечены подставным брендом.",
["loc_trai_16_03"] = "Датчики отключены! Теперь давайте доберемся до печатных пластин. Вагоны будут маркированы именем компании из манифеста.",
["loc_trai_17_01"] = "Давайте возьмем эти пластины, друзья. Ищите вагоны, отмеченные подставной грузовой компанией.",
["loc_trai_17_02"] = "Доберитесь до вагонов с фальшивым брендом. Пластины будут внутри.",
["loc_trai_17_03"] = "Мы знаем, в каких вагонах находятся пластины. Осталось только их найти.",
["loc_trai_18_01"] = "Вот оно. Пластины должны быть в этих вагонах.",
["loc_trai_18_02"] = "Вы нашли его! Это вагон с печатными пластинами.",
["loc_trai_18_03"] = "Это армейский вагон. Пластины должны быть внутри этого вагона.",
["loc_trai_19_01"] = "Хм, металл на этом поезде выглядит чертовски плотным. Помню, наш контакт говорил что-то о горелках на складе. Это должно помочь.",
["loc_trai_19_02"] = "Ох, замки на этих вагонах серьезные. Было бы гораздо проще просто прожечь обшивку. Контакт Джеммы упоминал горелки на складе. Загляните туда.",
["loc_trai_19_03"] = "Броня на этом поезде выглядит прочной, но я уверен, что немного экстремального жара решит проблему. Джемма говорит, что на складе есть горелки. Это именно то, что нам нужно.",
["loc_trai_20A_01"] = "Горелка! Всегда полезный инструмент.",
["loc_trai_20A_02"] = "Вы нашли горелку! Она может оказаться полезной.",
["loc_trai_20A_03"] = "Уверен, что эта горелка нам пригодится.",
["loc_trai_20_01"] = "Идите за горелкой на склад. Она нам понадобится, чтобы попасть внутрь вагонов.",
["loc_trai_20_02"] = "На складе есть горелки. Возьмите их.",
["loc_trai_20_03"] = "Найдите эти горелки. Они, вероятно, где-то заперты.",
["loc_trai_21_01"] = "Пора обезопасить печатные пластины. У вас есть всё необходимое, чтобы проникнуть в вагоны.",
["loc_trai_21_02"] = "Вы готовы вскрывать вагоны. Печатные пластины, ждите нас!",
["loc_trai_21_03"] = "Вы знаете, что делать. Проникайте в вагоны и забирайте пластины.",
["loc_trai_22_01"] = "Давайте упакуем эти печатные пластины.",
["loc_trai_22_02"] = "Попадайте внутрь этих вагонов.",
["loc_trai_22_03"] = "Сегодня мы заберём эти пластины, да?",
["loc_trai_23_01"] = "Похоже, на сейфе стоит RFID-блок. Проверьте внутри, чтобы найти провода нужного цвета, а после этого можно отключить замок.",
["loc_trai_23_02"] = "Старый добрый RFID-блок! Проверьте его, чтобы найти нужный провод, затем перережьте соответствующий снаружи вагона.",
["loc_trai_23_03"] = "Мы уже сталкивались с RFID-блоками. Проверьте внутри, чтобы узнать, какой провод нужно перерезать снаружи вагона. Ну, вы поняли.",
["loc_trai_24A_01"] = "Вы уверены, что это был нужный провод?",
["loc_trai_24A_02"] = "Не думаю, что это был он...",
["loc_trai_24A_03"] = "Неверный провод! Может, нам повезёт... а может, и нет.",
["loc_trai_24B_01"] = "Отличная память! Сейф должен быть открыт.",
["loc_trai_24B_02"] = "Вот оно! RFID-блок больше не помеха.",
["loc_trai_24B_03"] = "Вы выбрали правильный провод! Какое облегчение.",
["loc_trai_24_01"] = "Провода RFID должны быть расположены снаружи вагона. Убедитесь, что режете правильный.",
["loc_trai_24_02"] = "Провода RFID находятся на внешней стороне вагона. Не перепутайте провод по ошибке.",
["loc_trai_24_03"] = "Помните, друзья: если вы перережете не тот провод, включится сигнализация, и нам станет гораздо сложнее.",
["loc_trai_25_01"] = "Превосходно! Загружайте пластины на наш поезд для побега.",
["loc_trai_25_02"] = "Отлично сработано! Перемещайте пластины на поезд, который мы отметили для побега.",
["loc_trai_25_03"] = "Перенесите пластины на поезд для побега. Не оставляйте ничего!",
["loc_trai_26_01"] = "Теперь, когда мы загрузили поезд, нужно заправить его и подготовить к отправке. Подключите меня к системе оповещения депо. Я сделаю так, чтобы наша работа выглядела как обычный процесс.",
["loc_trai_26_02"] = "Нужно подготовить наш поезд для побега, но мы не должны привлекать внимание в депо. Если вы подключите меня к системе оповещения, я сделаю так, чтобы всё выглядело рутинно.",
["loc_trai_26_03"] = "Перед тем как заправить поезд для побега, подключите меня к системе оповещения депо. Я сделаю объявление, чтобы наша работа не вызывала подозрений.",
["loc_trai_27_01"] = "Внимание! Как делишки! Э-э, у нас тут изменение в расписании. Поезд C-33 нужно заправить и подготовить к отправлению. Так что двигайтесь, ребята! Чёрт побери!",
["loc_trai_27_02"] = "Привет всем! Поступил приказ сверху подготовить поезд C-33 к внеплановому отправлению. Так что если увидите, что этот поезд тронулся, не беспокойтесь. Всё в порядке.",
["loc_trai_27_03"] = "В расписании произошли небольшие изменения! Поезд C-33 должен уехать отсюда быстрее, чем индейка на День благодарения... Э-э... он скоро уедет. Вот и всё!",
["loc_trai_28_01"] = "Подключите меня к системе оповещения. Я всю неделю работал над своим техасским акцентом.",
["loc_trai_28_02"] = "Подключите меня к системе оповещения. У меня уже готов техасский акцент.",
["loc_trai_28_03"] = "Подождите, пока не услышите мой техасский акцент! Вы меня даже не узнаете.",
["loc_trai_29_01"] = "Рабочий мешает! Нас могут поймать, если мы будем долго ждать. Свяжите его, а затем продолжайте готовить локомотив.",
["loc_trai_29_02"] = "Похоже, один из рабочих не поверил моему акценту. Не понимаю, почему! Нам нужно его связать, чтобы закончить подготовку локомотива.",
["loc_trai_29_03"] = "Мы не можем подготовить локомотив, пока этот рабочий мешает! Разберитесь с ним. Нелетально, если сможете.",
["loc_trai_30_01"] = "Нужно отсоединить локомотив, заправить его и запустить.",
["loc_trai_30_02"] = "Вы уже подготовили поезд?",
["loc_trai_30_03"] = "Время - деньги, друзья. Подготовьте поезд к отправлению.",
["loc_trai_31_01"] = "Почти готово! Осталось найти элементы управления поворотным кругом. Эти системы обычно требуют ключ-карту, так что ищите рабочего с ней.",
["loc_trai_31_02"] = "Последнее, что нужно сделать, - повернуть поворотный круг. Найдите элементы управления и следите за рабочими поблизости. Если система требует ключ-карту, у них она должна быть.",
["loc_trai_31_03"] = "Заключительный этап: нужно развернуть наш поезд. Найдите элементы управления поворотным кругом, и если потребуется ключ-карта, один из рабочих должен её иметь.",
["loc_trai_32_01"] = "Найдите элементы управления поворотным кругом. Возможно, потребуется ключ-карта для доступа.",
["loc_trai_32_02"] = "Системы вроде поворотного круга обычно требуют ключ-карту. Вы, скорее всего, найдёте её у одного из рабочих.",
["loc_trai_32_03"] = "Этот поезд никуда не поедет, пока вы не повернёте поворотный круг.",
["loc_trai_33_01"] = "Почти готово! Осталось переориентировать поворотный круг. Используйте найденную ключ-карту, чтобы попасть в комнату управления.",
["loc_trai_33_02"] = "Последнее, что нужно сделать, - повернуть поворотный круг. Используйте найденную ключ-карту для доступа к элементам управления.",
["loc_trai_33_03"] = "Заключительный этап: нужно развернуть наш поезд. Найденная ключ-карта должна открыть доступ к элементам управления поворотным кругом.",
["loc_trai_34_01"] = "Эта ключ-карта открывает элементы управления поворотным кругом. Отличная находка!",
["loc_trai_34_02"] = "Сохраните эту карту. Она даст вам доступ к управлению поворотным кругом.",
["loc_trai_34_03"] = "Думаю, это ключ-карта для управления поворотным кругом. Она пригодится.",
["loc_trai_35_01"] = "Отлично! Теперь используйте элементы управления, чтобы развернуть наш поезд в нужную сторону.",
["loc_trai_35_02"] = "Давайте, поверните поворотный круг.",
["loc_trai_35_03"] = "Теперь возьмите управление поворотным кругом. Всё просто, нажмите кнопку.",
["loc_trai_36_01"] = "Используйте карту доступа, чтобы настроить поворотный круг.",
["loc_trai_36_02"] = "Разблокируйте управление поворотным кругом.",
["loc_trai_36_03"] = "Поворотный круг сам себя не повернёт.",
["loc_trai_37_01"] = "Чёрт! Похоже, в механизме поворотного круга короткое замыкание. Вам придётся починить его.",
["loc_trai_37_02"] = "Что-то пошло не так с поворотным кругом! Похоже, коротнуло цепь. Почините это как можно быстрее.",
["loc_trai_37_03"] = "Эх, ничего лёгкого! В поворотном круге короткое замыкание. Думаете, сможете это исправить?",
["loc_trai_38_01"] = "Почините короткое замыкание на поворотном круге. Будьте осторожны, вы на виду!",
["loc_trai_38_02"] = "Нужно починить поворотный круг. Быстрее!",
["loc_trai_38_03"] = "Не попадитесь, пока чините поворотный круг.",
["loc_trai_39_01"] = "Вы сделали это! Хорошо, возвращайтесь к поезду, и поехали навстречу закату!",
["loc_trai_39_02"] = "Всё готово! Все на поезд для побега!",
["loc_trai_39_03"] = "Пора уезжать! Прыгайте на поезд! Ну, вы понимаете, чух-чух и всё такое!",
["loc_trai_40_01"] = "Побег полностью готов! Назад к локомотиву, друзья!",
["loc_trai_40_02"] = "Пора выбираться отсюда!",
["loc_trai_40_03"] = "Больше незачем задерживаться! Возвращайтесь к поезду для побега!",
["loc_trai_41_01"] = "Чёрт возьми! Это будет интересно!",
["loc_trai_41_02"] = "Внимательнее, друзья!",
["loc_trai_41_03"] = "Ладно! Заряжаем и в бой!",
["loc_trai_42_01"] = "Они готовят поезда к побегу! Быстрее в депо!",
["loc_trai_42_02"] = "Они пытаются сбежать! Не дайте этим поездам уйти!",
["loc_trai_42_03"] = "Быстрее в депо! Если поезда уйдут, дело пропало!",
["loc_trai_43_01"] = "Время поджимает, друзья! Пробейтесь через первые ворота!",
["loc_trai_43_02"] = "Давайте, пройдите через ворота! Нет времени на раздумья!",
["loc_trai_43_03"] = "Ускорьтесь, или мы попрощаемся с этими пластинами!",
["loc_trai_44_01"] = "Вторые ворота хорошо укреплены, но мы можем обойти их через гараж. Контакт Джеммы спрятал поблизости термит. Найдите его!",
["loc_trai_44_02"] = "Инсайдер Джеммы спрятал поблизости термит. Он не поможет с следующими воротами, но позволит нам попасть в гараж, соединённый с депо.",
["loc_trai_44_03"] = "Следующие ворота не шутят. У нас больше шансов пройти через гараж. Ищите мешок с термитом, который оставил инсайдер Джеммы.",
["loc_trai_45_01"] = "Давайте! Используйте термит, чтобы попасть в гараж!",
["loc_trai_45_02"] = "Когда найдёте термит, используйте его, чтобы войти в гараж!",
["loc_trai_45_03"] = "Примените термит на двери гаража! Мы теряем время!",
["loc_trai_46_01"] = "Нам нужно остановить поезда от отправления! Похоже, армия припарковала вокруг депо несколько Хамви. Посмотрите, есть ли там взрывчатка.",
["loc_trai_46_02"] = "Мы не можем позволить поездам уйти с нашими пластинами! Проверьте Хамви на наличие взрывчатки.",
["loc_trai_46_03"] = "Нам понадобится взрывчатка, чтобы остановить эти поезда. Осмотрите Хамви, припаркованные на территории.",
["loc_trai_47_01"] = "Проверьте Хамви на наличие взрывчатки.",
["loc_trai_47_02"] = "Есть взрывчатка в этих Хамви?",
["loc_trai_47_03"] = "Думаю, вы найдёте взрывчатку в этих армейских машинах.",
["loc_trai_48_01"] = "Хорошая находка! Установите эту взрывчатку на трубопровод над рельсами. Я подорву её, когда вы отойдёте, и она заблокирует побег.",
["loc_trai_48_02"] = "Установите взрывчатку на трубопровод над рельсами. Я взорву её, когда вы будете на безопасном расстоянии, и взрыв должен остановить поезда.",
["loc_trai_48_03"] = "Думаю, если мы подорвём трубопровод над рельсами, мы сможем заблокировать поезда. Установите взрывчатку. Она не сработает, пока вы не отойдёте.",
["loc_trai_49A_01"] = "Три... Два... Один!",
["loc_trai_49A_02"] = "Готовьтесь... Вперёд... Бум!",
["loc_trai_49A_03"] = "Здесь... Мы... Идём!",
["loc_trai_49_01"] = "Теперь убирайтесь из зоны взрыва!",
["loc_trai_49_02"] = "Выйдите из зоны взрыва!",
["loc_trai_49_03"] = "Прикройтесь, друзья!",
["loc_trai_50_01"] = "Установите взрывчатку на трубопровод! Поезд может уйти в любой момент!",
["loc_trai_50_02"] = "Поезда уходят! Установите взрывчатку, быстрее!",
["loc_trai_50_03"] = "Подготовьте трубопровод к взрыву! Пока не стало слишком поздно!",
["loc_trai_51_01"] = "Теперь нам нужно попасть в административный офис, чтобы узнать, какие поезда перевозят пластины. Дверь, вероятно, заблокирована, так что начинайте сверлить!",
["loc_trai_51_02"] = "Пора выяснить, какой поезд перевозит пластины. Просверлите дверь в административный офис. Там хранится транспортная накладная.",
["loc_trai_51_03"] = "В административном офисе находится транспортная накладная, которая подскажет, в каком поезде находятся пластины. Используйте дрель, чтобы попасть внутрь.",
["loc_trai_52_01"] = "Просверлите дверь в административный офис!",
["loc_trai_52_02"] = "Взломайте административный офис!",
["loc_trai_52_03"] = "Попадите внутрь административного офиса!",
["loc_trai_53_01"] = "Взломайте компьютер и откройте накладную. Она подскажет, какая транспортная компания является прикрытием.",
["loc_trai_53_02"] = "Откройте транспортную накладную на этом компьютере. Нам нужно узнать, какой бренд используется армией как прикрытие.",
["loc_trai_53_03"] = "Транспортная накладная хранится на компьютере в административном офисе. Взломайте его, чтобы узнать, где хранятся пластины.",
["loc_trai_54_01"] = "Скорее за компьютер! Кибербезопасность здесь должна быть на уровне кактуса.",
["loc_trai_54_02"] = "Вы сможете взломать этот компьютер без проблем!",
["loc_trai_54_03"] = "Нам нужно взглянуть на эту накладную!",
["loc_trai_55_01"] = "Итак, мы знаем, какой поезд перевозит печатные пластины. Найдите вагоны с поддельным брендом.",
["loc_trai_55_02"] = "Итак, это фальшивый бренд транспортной компании. Найдите вагоны с этим логотипом. Внутри будут печатные пластины.",
["loc_trai_55_03"] = "Этот транспортный бренд - прикрытие для армии. Найдите эти вагоны, и вы найдете пластины.",
["loc_trai_56_01"] = "Найдите вагоны с брендом из накладной.",
["loc_trai_56_02"] = "Ищите вагоны с поддельным логотипом.",
["loc_trai_56_03"] = "Теперь мы знаем, в каких вагонах находятся пластины. Нужно только их найти.",
["loc_trai_57_01"] = "Похоже, на этих вагонах толстый металл. Наш контакт сказал что-то про горелки, хранящиеся на складе. Идите за ними!",
["loc_trai_57_02"] = "Горелки смогут прожечь броню на этих вагонах. Контакт Джеммы говорит, что они хранятся где-то на складе.",
["loc_trai_57_03"] = "Эти вагоны выглядят крепкими, но не обязательно термостойкими. Наш информатор говорит, что горелки есть на складе. Вы знаете, что делать.",
["loc_trai_58_01"] = "Вы найдете горелки, запертые на складе.",
["loc_trai_58_02"] = "Они хранят горелки на складе.",
["loc_trai_58_03"] = "Идите за горелками на склад.",
["loc_trai_59_01"] = "Пластины уже близко! Осталось только прожечь путь в вагоны.",
["loc_trai_59_02"] = "Вы готовы взломать эти вагоны. Печатные пластины, встречайте нас!",
["loc_trai_59_03"] = "Как только вы прожжете путь в вагоны, эти пластины будут нашими!",
["loc_trai_60_01"] = "Вскрывайте вагоны и забирайте пластины!",
["loc_trai_60_02"] = "Используйте свою горелку, чтобы попасть в вагон поезда.",
["loc_trai_60_03"] = "Давайте, друзья! Берите горелку и работайте!",
["loc_trai_61_01"] = "На этом проклятом сейфе блок RFID! Запустите взлом, и когда он откроется, забирайте пластины.",
["loc_trai_61_02"] = "Они поставили эти глупые блоки RFID! Нам уже всё равно на сигнализацию. Просто запустите взлом замка.",
["loc_trai_61_03"] = "О, отлично, блок RFID. Мы так их обожаем. Запустите взлом, чтобы открыть сейф.",
["loc_trai_62_01"] = "Убедитесь, что никто не тронет провода снаружи вагона!",
["loc_trai_62_02"] = "Взлом будет прерван, если кто-то вмешается в провода снаружи вагона.",
["loc_trai_62_03"] = "Снаружи вагона есть сеть проводов RFID. Защитите их.",
["loc_trai_63_01"] = "Черт, кто-то перерезал провод RFID! Вам придется перезагрузить взлом.",
["loc_trai_63_02"] = "Что-то случилось с одним из проводов RFID! перезагрузить процесс взлома!",
["loc_trai_63_03"] = "Взлом остановился! Можете перезагрузить его?",
["loc_trai_64_01"] = "Держитесь плана! Погрузите пластины на наш поезд для побега.",
["loc_trai_64_02"] = "Отнесите эти пластины к нашему поезду для побега! Вы отлично справляетесь!",
["loc_trai_64_03"] = "Не отвлекайтесь! Переносите пластины на наш поезд для побега.",
["loc_trai_65_01"] = "Этот побег может быть немного сумасшедшим, друзья. Сначала заправьте наш локомотив и отсоедините его от вагонов.",
["loc_trai_65_02"] = "Прежде чем мы сделаем что-либо ещё, вам нужно заправить локомотив и отсоединить его от вагонов.",
["loc_trai_65_03"] = "Мы будем готовить побег шаг за шагом. Шаг первый: заправьте локомотив и отсоедините его от вагонов.",
["loc_trai_66_01"] = "Подготовьте локомотив к отправлению! Чем быстрее вы работаете, тем быстрее мы уйдем!",
["loc_trai_66_02"] = "Давайте не будем терять времени, друзья! Подготовьте локомотив для нашего побега!",
["loc_trai_66_03"] = "Нам нужно подготовить поезд к отправлению! Действуйте быстро!",
["loc_trai_67_01"] = "Хорошо, вот сложная часть. Поворотный круг заблокирован, но на месте есть кран для подъема тяжелых грузов. Надеюсь, он достаточно прочный, чтобы переместить наш локомотив на свободный путь. Управляйте краном, чтобы установить его в нужное положение.",
["loc_trai_67_02"] = "Придется потерпеть. Они заблокировали поворотный круг, но грузовой кран все еще работает. Я на семьдесят процентов уверен, что он сможет поднять наш локомотив на свободный путь. Доберитесь до пульта управления, и давайте это проверим!",
["loc_trai_67_03"] = "С заблокированным поворотным кругом грузовой кран - наш лучший шанс переместить локомотив на свободный путь. Направляйтесь к пульту управления, и будем надеяться, что это из тех случаев, когда безумная идея сработает.",
["loc_trai_68_01"] = "Установите кран над локомотивом. Это наш лучший шанс выбраться отсюда!",
["loc_trai_68_02"] = "Позиционируйте кран!",
["loc_trai_68_03"] = "Установите кран в нужное положение!",
["loc_trai_69_01"] = "Вам нужно вручную закрепить крюки крана. Эта машина не была рассчитана на такие сумасшедшие задачи.",
["loc_trai_69_02"] = "Теперь поднимайтесь на поезд и закрепите крюки. Чем крепче, тем лучше.",
["loc_trai_69_03"] = "Этот кран предназначен для подъема грузовых контейнеров, а не поездов для побега. Вам придется вручную закрепить крюки.",
["loc_trai_70_01"] = "Закрепите крюки на крыше нашего поезда!",
["loc_trai_70_02"] = "Закрепите эти крюки как следует!",
["loc_trai_70_03"] = "Поднимайтесь на поезд и закрепите крюки!",
["loc_trai_71_01"] = "Момент истины. Используйте кран, чтобы переместить наш локомотив. Представьте, что это один из тех автоматов с клешней, только больше и с гораздо более высокими ставками!",
["loc_trai_71_02"] = "Ладно, управляйте краном, чтобы поднять наш локомотив на правильный путь. Ах, черт, я не могу смотреть...",
["loc_trai_71_03"] = "Выглядит хорошо! Теперь используйте пульт управления краном, чтобы переместить локомотив. Я уверен, что это сработает! Ну, может, не совсем уверен, но я очень оптимистичен!",
["loc_trai_72_01"] = "Активируйте кран. Надеюсь, это сработает!",
["loc_trai_72_02"] = "Посмотрим, на что способен этот кран!",
["loc_trai_72_03"] = "Сейчас или никогда! Включите кран!",
["loc_trai_73A_01"] = "Держите этих парней подальше от управления краном!",
["loc_trai_73A_02"] = "Эти ребята испортят управление краном, если вы им позволите!",
["loc_trai_73A_03"] = "Не дайте этим парням вмешаться в управление краном!",
["loc_trai_73B_01"] = "Они остановили кран! Вам нужно починить управление!",
["loc_trai_73B_02"] = "Кто-то добрался до управления! Чините быстрее!",
["loc_trai_73B_03"] = "Кран остановлен! Верните его в рабочее состояние!",
